class DSU {
    private val parent: LongArray
    private val rank: LongArray

    constructor(n: Long) {
        parent = LongArray(n.toInt())
        rank = LongArray(n.toInt())
        for (i in 0 until n.toInt()) {
            parent[i] = i.toLong()
            rank[i] = 1L
        }
    }

    fun find(x: Long): Long {
        if (parent[x.toInt()] != x) {
            parent[x.toInt()] = find(parent[x.toInt()])
        }
        return parent[x.toInt()]
    }

    fun union(x: Long, y: Long): Boolean {
        val xroot = find(x)
        val yroot = find(y)
        if (xroot == yroot) return false
        if (rank[xroot.toInt()] < rank[yroot.toInt()]) {
            parent[xroot.toInt()] = yroot
        } else {
            parent[yroot.toInt()] = xroot
            if (rank[xroot.toInt()] == rank[yroot.toInt()]) {
                rank[xroot.toInt()] += 1
            }
        }
        return true
    }
}

fun solve(n: Long, edges: Array<Array<Long>>, k: Long): Long {
    var low = 0L
    var high = 0L
    for (e in edges) {
        high = max(high, e[2])
    }

    while (low < high) {
        val mid = (low + high) / 2
        val dsu = DSU(n)
        var components = n.toInt()
        for (e in edges) {
            if (e[2] <= mid) {
                val u = e[0]
                val v = e[1]
                if (dsu.find(u) != dsu.find(v)) {
                    dsu.union(u, v)
                    components--
                }
            }
        }
        if (components <= k.toInt()) {
            high = mid
        } else {
            low = mid + 1
        }
    }
    return low
}
