class DSU {
    private val parent: MutableList<Int>
    private val rank: MutableList<Int>

    constructor(n: Int) {
        parent = MutableList(n) { it }
        rank = MutableList(n) { 1 }
    }

    fun find(x: Int): Int {
        if (parent[x] != x) {
            parent[x] = find(parent[x])
        }
        return parent[x]
    }

    fun union(x: Int, y: Int): Boolean {
        val xroot = find(x)
        val yroot = find(y)
        if (xroot == yroot) return false
        if (rank[xroot] < rank[yroot]) {
            parent[xroot] = yroot
        } else {
            parent[yroot] = xroot
            if (rank[xroot] == rank[yroot]) {
                rank[xroot]++
            }
        }
        return true
    }
}

