#include <vector>
using namespace std;

class DSU {
    vector<int> parent, rank;
public:
    DSU(int n) : parent(n), rank(n) {
        for (int i = 0; i < n; ++i) {
            parent[i] = i;
            rank[i] = 1;
        }
    }
    int find(int x) {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }
    bool union_(int x, int y) {
        int xroot = find(x);
        int yroot = find(y);
        if (xroot == yroot) return false;
        if (rank[xroot] < rank[yroot]) {
            parent[xroot] = yroot;
        } else {
            parent[yroot] = xroot;
            if (rank[xroot] == rank[yroot]) {
                ++rank[xroot];
            }
        }
        return true;
    }
};

long long solve(long long n, vector<vector<long long>> edges, long long k) {
    long long low = 0, high = 0;
    for (auto& e : edges) {
        high = max(high, e[2]);
    }

    while (low < high) {
        long long mid = (low + high) / 2;
        DSU dsu(n);
        int components = n;
        for (auto& e : edges) {
            if (e[2] <= mid) {
                int u = e[0], v = e[1];
                if (dsu.find(u) != dsu.find(v)) {
                    dsu.union_(u, v);
                    components--;
                }
            }
        }
        if (components <= k) {
            high = mid;
        } else {
            low = mid + 1;
        }
    }
    return low;
}
